#!/usr/bin/env node
// Installs git hooks that delegate to npm scripts.
// Run once after cloning: bun run hooks:install

import { writeFileSync, chmodSync, existsSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const root = join(dirname(fileURLToPath(import.meta.url)), '..');
const hooksDir = join(root, '.git', 'hooks');

if (!existsSync(hooksDir)) {
  console.error('No .git/hooks directory found. Are you in the repo root?');
  process.exit(1);
}

const preCommit = `#!/bin/sh
# Generated by scripts/install-hooks.js — do not edit directly.

# 1. Auto-format and re-stage any files that changed
STAGED=$(git diff --cached --name-only --diff-filter=ACMR)
bun run format
echo "$STAGED" | xargs -r git add

# 2. Run checks (typecheck, lint, tests)
bun run pre-commit
`;

const hookPath = join(hooksDir, 'pre-commit');
writeFileSync(hookPath, preCommit, 'utf8');
chmodSync(hookPath, 0o755);
console.log('✓ pre-commit hook installed');
